<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8" />
<meta name="viewport" content="width=device-width, initial-scale=1.0" />
<title>International Vedic Academy — Unlock Ancient Wisdom for Modern Success</title>
<meta name="description" content="Master Vedic Astrology, Tarot, Numerology, Vastu, Palmistry, Crystal & Reiki Healing online. Learn from expert mentors with certified, career-focused programs at International Vedic Academy." />
<link rel="preconnect" href="https://fonts.googleapis.com">
<link href="https://cdn.jsdelivr.net/npm/bootstrap@5.3.2/dist/css/bootstrap.min.css" rel="stylesheet">
<link rel="preconnect" href="https://fonts.gstatic.com" crossorigin>
<link href="https://fonts.googleapis.com/css2?family=Cormorant+Garamond:ital,wght@0,400;0,500;0,600;0,700;1,400;1,500&family=Fraunces:ital,opsz,wght@0,9..144,300;0,9..144,400;0,9..144,500;0,9..144,600;0,9..144,700;1,9..144,400&family=Inter:wght@300;400;500;600;700&display=swap" rel="stylesheet">
<style>
  :root {
    /* Cream / Beige palette */
    --bg-cream: #f7f1e3;
    --bg-cream-deep: #f0e8d3;
    --bg-white: #ffffff;
    --bg-card: #ffffff;
    --ink: #1a1535;
    --ink-soft: #4a4365;
    --ink-muted: #7a7290;

    /* Cosmic dark for accents */
    --cosmic-deep: #0a0618;
    --cosmic-mid: #1a1535;
    --cosmic-purple: #2a1f5e;
    --cosmic-violet: #4a2f8e;

    /* Gold accents */
    --gold: #d4a24c;
    --gold-bright: #f0c878;
    --gold-deep: #a8791f;

    /* Borders & shadows */
    --border-light: rgba(26, 21, 53, 0.08);
    --border-gold: rgba(212, 162, 76, 0.3);
    --shadow-sm: 0 4px 12px rgba(26, 21, 53, 0.06);
    --shadow-md: 0 8px 24px rgba(26, 21, 53, 0.08);
    --shadow-lg: 0 20px 50px rgba(26, 21, 53, 0.12);
    --shadow-cosmic: 0 30px 80px rgba(10, 6, 24, 0.4);

    --serif: 'Fraunces', Georgia, serif;
    --serif-display: 'Cormorant Garamond', Georgia, serif;
    --sans: 'Inter', sans-serif;
  }

  * { margin: 0; padding: 0; box-sizing: border-box; }
  html { scroll-behavior: smooth; }
  body {
    font-family: var(--sans);
    background:
      linear-gradient(180deg, rgba(247, 241, 227, 0.5), rgba(247, 241, 227, 0.5)),
      url('data:image/jpeg;base64,') top center / 100% auto repeat-y,
      var(--bg-cream);
    color: var(--ink);
    overflow-x: hidden;
    line-height: 1.6;
  }

  .container {
    max-width: 1280px;
    margin: 0 auto;
    padding: 0 32px;
  }

  /* ============ HERO COSMIC BACKGROUND (Hybrid: image base + animated overlays) ============ */
  .hero-bg {
    position: relative;
    overflow: hidden;
    min-height: 640px;
    /* Image as static base layer - sized so mountains/sun show clearly at bottom */
    background:
      url('data:image/jpeg;base64,') center bottom / 120% auto no-repeat,
      linear-gradient(180deg, #0a0618 0%, #0a0618 45%, #14102a 75%, #1a1535 100%);
  }

  /* Subtle readability gradient for headline text on the left side */
  .hero-bg::before {
    content: '';
    position: absolute;
    inset: 0;
    background: linear-gradient(90deg,
      rgba(10, 6, 24, 0.78) 0%,
      rgba(10, 6, 24, 0.55) 25%,
      rgba(10, 6, 24, 0.25) 50%,
      rgba(10, 6, 24, 0.05) 75%,
      rgba(10, 6, 24, 0) 100%);
    z-index: 1;
    pointer-events: none;
  }

  /* Bottom fade to cream so it blends into stats section */
  .hero-bg::after {
    content: '';
    position: absolute;
    bottom: -1px;
    left: 0; right: 0;
    height: 30px;
    background: linear-gradient(180deg, transparent, var(--bg-cream));
    z-index: 2;
    pointer-events: none;
  }

  /* Animated twinkling sparkles layered on top of the image */
  .hero-stars {
    position: absolute;
    inset: 0;
    pointer-events: none;
    z-index: 2;
    background:
      /* Tiny distant stars */
      radial-gradient(0.5px 0.5px at 10% 12%, rgba(255,255,255,0.9), transparent),
      radial-gradient(0.5px 0.5px at 22% 8%, rgba(255,245,210,0.7), transparent),
      radial-gradient(0.5px 0.5px at 35% 15%, rgba(255,255,255,0.8), transparent),
      radial-gradient(0.5px 0.5px at 48% 6%, rgba(255,245,210,0.7), transparent),
      radial-gradient(0.5px 0.5px at 62% 18%, rgba(255,255,255,0.9), transparent),
      radial-gradient(0.5px 0.5px at 75% 10%, rgba(255,245,210,0.6), transparent),
      radial-gradient(0.5px 0.5px at 88% 22%, rgba(255,255,255,0.8), transparent),
      radial-gradient(0.5px 0.5px at 95% 8%, rgba(255,245,210,0.7), transparent),
      radial-gradient(0.5px 0.5px at 5% 32%, rgba(255,255,255,0.6), transparent),
      radial-gradient(0.5px 0.5px at 18% 28%, rgba(255,245,210,0.7), transparent),
      radial-gradient(0.5px 0.5px at 42% 32%, rgba(255,255,255,0.5), transparent),
      radial-gradient(0.5px 0.5px at 58% 28%, rgba(255,245,210,0.6), transparent),
      radial-gradient(0.5px 0.5px at 72% 35%, rgba(255,255,255,0.7), transparent),
      radial-gradient(0.5px 0.5px at 92% 32%, rgba(255,245,210,0.5), transparent),
      radial-gradient(0.5px 0.5px at 12% 48%, rgba(255,255,255,0.6), transparent),
      radial-gradient(0.5px 0.5px at 38% 52%, rgba(255,245,210,0.5), transparent),
      radial-gradient(0.5px 0.5px at 65% 50%, rgba(255,255,255,0.7), transparent),
      radial-gradient(0.5px 0.5px at 85% 55%, rgba(255,245,210,0.5), transparent),
      /* Slightly bigger stars (medium) */
      radial-gradient(1px 1px at 28% 18%, rgba(255,255,255,0.9), transparent),
      radial-gradient(1px 1px at 55% 14%, rgba(255,245,210,0.8), transparent),
      radial-gradient(1px 1px at 82% 16%, rgba(255,255,255,0.9), transparent),
      radial-gradient(1px 1px at 15% 40%, rgba(255,245,210,0.7), transparent),
      radial-gradient(1px 1px at 48% 42%, rgba(255,255,255,0.8), transparent),
      radial-gradient(1px 1px at 78% 45%, rgba(255,245,210,0.7), transparent),
      /* Bright "hero" stars with gentle glow */
      radial-gradient(1.5px 1.5px at 32% 22%, rgba(255,255,255,1), transparent),
      radial-gradient(1.5px 1.5px at 70% 12%, rgba(255,245,210,0.95), transparent),
      radial-gradient(1.5px 1.5px at 50% 38%, rgba(255,255,255,1), transparent);
    background-size: 100% 100%;
    animation: twinkleField 4s ease-in-out infinite alternate;
  }
  @keyframes twinkleField {
    0% { opacity: 0.5; }
    100% { opacity: 1; }
  }

  /* Second star layer — twinkling on offset cycle for variety */
  .hero-stars-2 {
    position: absolute;
    inset: 0;
    pointer-events: none;
    z-index: 2;
    background:
      radial-gradient(1px 1px at 8% 20%, rgba(255,255,255,0.8), transparent),
      radial-gradient(1px 1px at 25% 6%, rgba(255,245,210,0.7), transparent),
      radial-gradient(1px 1px at 40% 26%, rgba(255,255,255,0.9), transparent),
      radial-gradient(1px 1px at 60% 8%, rgba(255,245,210,0.8), transparent),
      radial-gradient(1px 1px at 88% 38%, rgba(255,255,255,0.7), transparent),
      radial-gradient(1px 1px at 5% 55%, rgba(255,245,210,0.6), transparent),
      radial-gradient(1px 1px at 30% 60%, rgba(255,255,255,0.7), transparent),
      radial-gradient(1px 1px at 95% 50%, rgba(255,245,210,0.6), transparent);
    animation: twinkleField 5s ease-in-out infinite alternate;
    animation-delay: -2s;
  }

  /* Golden dust particles (subtle) */
  .hero-dust {
    position: absolute;
    inset: 0;
    pointer-events: none;
    z-index: 3;
    opacity: 0.45;
    background:
      radial-gradient(0.5px 0.5px at 18% 75%, rgba(255, 200, 130, 0.9), transparent),
      radial-gradient(0.5px 0.5px at 26% 78%, rgba(255, 200, 130, 0.8), transparent),
      radial-gradient(0.5px 0.5px at 35% 76%, rgba(255, 200, 130, 0.9), transparent),
      radial-gradient(0.5px 0.5px at 45% 80%, rgba(255, 200, 130, 0.8), transparent),
      radial-gradient(0.5px 0.5px at 55% 75%, rgba(255, 200, 130, 0.9), transparent),
      radial-gradient(0.5px 0.5px at 65% 78%, rgba(255, 200, 130, 0.8), transparent),
      radial-gradient(0.5px 0.5px at 75% 76%, rgba(255, 200, 130, 0.9), transparent),
      radial-gradient(0.5px 0.5px at 82% 80%, rgba(255, 200, 130, 0.8), transparent);
    animation: dustDrift 8s ease-in-out infinite alternate;
  }
  @keyframes dustDrift {
    0% { transform: translateY(0); opacity: 0.3; }
    100% { transform: translateY(-12px); opacity: 0.6; }
  }



  /* ============ HEADER ============ */
  header {
    position: relative;
    z-index: 10;
  }
  .nav {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 24px 0;
  }
  .logo {
    display: flex;
    align-items: center;
    gap: 14px;
    text-decoration: none;
    color: #faf5ea;
  }
  .logo-mark {
    width: 46px;
    height: 46px;
    border: 1.5px solid var(--gold);
    border-radius: 50%;
    display: grid;
    place-items: center;
    background: radial-gradient(circle, rgba(212,162,76,0.2), transparent);
  }
  .logo-mark svg { width: 26px; height: 26px; color: var(--gold-bright); }
  .logo-text {
    font-family: var(--serif-display);
    font-size: 17px;
    letter-spacing: 2px;
    font-weight: 500;
    text-transform: uppercase;
    line-height: 1.1;
    color: #faf5ea;
  }
  .logo-text span {
    display: block;
    font-size: 11px;
    letter-spacing: 4px;
    color: var(--gold);
    margin-top: 2px;
  }
  nav ul {
    list-style: none;
    display: flex;
    gap: 36px;
    align-items: center;
  }
  nav ul a {
    color: #e8e0d0;
    text-decoration: none;
    font-size: 14px;
    font-weight: 400;
    letter-spacing: 0.3px;
    transition: color 0.3s;
    position: relative;
    padding: 4px 0;
  }
  nav ul a:hover { color: var(--gold-bright); }
  nav ul a.active {
    color: var(--gold-bright);
  }
  nav ul a.active::after {
    content: '';
    position: absolute;
    bottom: -4px;
    left: 0; right: 0;
    height: 2px;
    background: var(--gold);
    border-radius: 2px;
  }
  .nav-right {
    display: flex;
    gap: 12px;
    align-items: center;
  }
  .nav-search {
    width: 38px;
    height: 38px;
    border-radius: 50%;
    background: rgba(255, 255, 255, 0.08);
    border: 1px solid rgba(255, 255, 255, 0.15);
    display: grid;
    place-items: center;
    cursor: pointer;
    transition: all 0.3s;
  }
  .nav-search:hover { background: rgba(255, 255, 255, 0.15); }
  .nav-search svg { width: 16px; height: 16px; color: #faf5ea; }

  .btn {
    padding: 11px 22px;
    border-radius: 50px;
    font-family: var(--sans);
    font-size: 13px;
    letter-spacing: 0.3px;
    cursor: pointer;
    transition: all 0.3s;
    text-decoration: none;
    display: inline-flex;
    align-items: center;
    gap: 8px;
    border: none;
    font-weight: 500;
  }
  .btn-outline-light {
    background: transparent;
    color: #faf5ea;
    border: 1px solid rgba(255, 255, 255, 0.3);
  }
  .btn-outline-light:hover { border-color: var(--gold); color: var(--gold-bright); }
  .btn-gold {
    background: linear-gradient(135deg, var(--gold-bright), var(--gold));
    color: #1a0f00;
    font-weight: 600;
    box-shadow: 0 6px 18px rgba(212, 162, 76, 0.35);
  }
  .btn-gold:hover { transform: translateY(-2px); box-shadow: 0 10px 24px rgba(212, 162, 76, 0.5); }
  .btn-dark {
    background: var(--cosmic-deep);
    color: #faf5ea;
  }
  .btn-dark:hover { transform: translateY(-2px); box-shadow: 0 8px 20px rgba(10, 6, 24, 0.3); }
  .btn-whatsapp {
    background: #25d366;
    color: white;
    font-weight: 600;
  }
  .btn-whatsapp:hover { transform: translateY(-2px); background: #1ebe5a; }

  /* ============ HERO ============ */
  .hero {
    padding: 50px 0 160px;
    position: relative;
    z-index: 3;
    min-height: 520px;
  }
  .hero-inner {
    display: grid;
    grid-template-columns: 1.2fr 1fr;
    gap: 30px;
    align-items: center;
    min-height: 380px;
  }
  .hero-content {
    color: #faf5ea;
    text-shadow: 0 2px 16px rgba(10, 6, 24, 0.6), 0 1px 3px rgba(10, 6, 24, 0.5);
    position: relative;
    z-index: 5;
  }
  .hero-content h1, .hero-content p, .hero-content .student-text {
    text-shadow: 0 2px 12px rgba(10, 6, 24, 0.7), 0 1px 3px rgba(10, 6, 24, 0.5);
  }
  .hero h1 {
    font-family: var(--serif);
    font-size: clamp(36px, 4.5vw, 60px);
    line-height: 1.05;
    font-weight: 500;
    color: #faf5ea;
    margin-bottom: 24px;
    letter-spacing: -1.5px;
  }
  .hero h1 .gold-text {
    color: var(--gold-bright);
    display: inline-block;
    background: linear-gradient(135deg, #f0c878, #d4a24c);
    -webkit-background-clip: text;
    background-clip: text;
    -webkit-text-fill-color: transparent;
  }
  .hero p.lead {
    font-size: 16px;
    color: #d8cfbd;
    max-width: 480px;
    margin-bottom: 32px;
    line-height: 1.7;
  }
  .hero-ctas {
    display: flex;
    gap: 14px;
    margin-bottom: 36px;
  }
  .btn-watch {
    background: rgba(255, 255, 255, 0.08);
    color: #faf5ea;
    border: 1px solid rgba(255, 255, 255, 0.2);
  }
  .btn-watch:hover { background: rgba(255, 255, 255, 0.15); }
  .btn-watch .play-icon {
    width: 18px;
    height: 18px;
    border-radius: 50%;
    background: rgba(255, 255, 255, 0.15);
    display: grid;
    place-items: center;
  }
  .btn-watch .play-icon::before {
    content: '';
    width: 0;
    height: 0;
    border-left: 6px solid #faf5ea;
    border-top: 4px solid transparent;
    border-bottom: 4px solid transparent;
    margin-left: 2px;
  }

  .student-row {
    display: flex;
    align-items: center;
    gap: 14px;
  }
  .avatars-stack { display: flex; }
  .avatars-stack .avatar {
    width: 38px;
    height: 38px;
    border-radius: 50%;
    border: 2px solid var(--cosmic-mid);
    margin-left: -12px;
    display: grid;
    place-items: center;
    font-weight: 600;
    color: #1a0f00;
    font-size: 13px;
    font-family: var(--serif);
  }
  .avatars-stack .avatar:first-child { margin-left: 0; background: linear-gradient(135deg, var(--gold-bright), #c4847a); }
  .avatars-stack .avatar:nth-child(2) { background: linear-gradient(135deg, var(--gold), #8b6a4f); }
  .avatars-stack .avatar:nth-child(3) { background: linear-gradient(135deg, #c4847a, #7a4f9e); }
  .avatars-stack .avatar:nth-child(4) { background: linear-gradient(135deg, #f0c878, #d4a24c); }
  .student-text strong {
    font-family: var(--sans);
    font-size: 15px;
    color: #faf5ea;
    font-weight: 600;
    display: block;
  }
  .student-text strong em {
    color: var(--gold-bright);
    font-style: normal;
  }
  .student-text span {
    font-size: 12px;
    color: #a89d87;
  }

  /* ============ HERO VISUAL (Animated overlays on top of image) ============ */
  .hero-visual {
    position: relative;
    aspect-ratio: 1.2 / 1;
    width: 100%;
    max-width: 460px;
    margin-left: auto;
    height: 100%;
    min-height: 380px;
  }
  .hv-scene {
    position: absolute;
    inset: 0;
    overflow: visible;
  }

  /* Sparkle points scattered */
  .hv-sparkle {
    position: absolute;
    width: 8px; height: 8px;
    z-index: 4;
    animation: twinkle 3s ease-in-out infinite;
  }
  .hv-sparkle::before, .hv-sparkle::after {
    content: '';
    position: absolute;
    background: #fff5e0;
    box-shadow: 0 0 8px rgba(255, 245, 200, 0.9);
  }
  .hv-sparkle::before {
    top: 50%; left: 0; right: 0;
    height: 1px;
    transform: translateY(-50%);
  }
  .hv-sparkle::after {
    left: 50%; top: 0; bottom: 0;
    width: 1px;
    transform: translateX(-50%);
  }
  @keyframes twinkle {
    0%, 100% { opacity: 0.3; transform: scale(0.8); }
    50% { opacity: 1; transform: scale(1.2); }
  }
  .hv-sparkle-1 { top: 18%; left: 22%; animation-delay: 0s; }
  .hv-sparkle-2 { top: 8%; right: 35%; animation-delay: -1s; }
  .hv-sparkle-3 { top: 40%; right: 6%; animation-delay: -1.5s; width: 6px; height: 6px; }
  .hv-sparkle-4 { bottom: 38%; left: 18%; animation-delay: -2s; width: 5px; height: 5px; }
  .hv-sparkle-5 { top: 55%; right: 28%; animation-delay: -0.5s; width: 6px; height: 6px; }

  /* Floating tarot cards — bigger, tilted, more prominent */
  .hv-card {
    position: absolute;
    width: 110px;
    aspect-ratio: 5/8;
    background:
      radial-gradient(ellipse at top, rgba(74, 47, 142, 0.6), transparent 70%),
      linear-gradient(165deg, #1f1648 0%, #14102a 50%, #0a0618 100%);
    border: 1.5px solid #d4a24c;
    border-radius: 10px;
    box-shadow:
      0 25px 60px rgba(0,0,0,0.85),
      0 0 50px rgba(212, 162, 76, 0.45),
      inset 0 0 30px rgba(212, 162, 76, 0.15);
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: space-between;
    padding: 14px 8px 10px;
    animation: floatY 6s ease-in-out infinite;
    z-index: 5;
  }
  /* Inner gold double-border frame */
  .hv-card::before {
    content: '';
    position: absolute;
    inset: 5px;
    border: 1px solid rgba(212, 162, 76, 0.55);
    border-radius: 6px;
    pointer-events: none;
  }
  /* Corner ornaments */
  .hv-card::after {
    content: '';
    position: absolute;
    inset: 9px;
    border: 0.5px solid rgba(240, 200, 120, 0.25);
    border-radius: 4px;
    pointer-events: none;
  }
  .hv-card .card-icon {
    width: 70%;
    aspect-ratio: 1;
    color: #f0c878;
    filter: drop-shadow(0 0 8px rgba(240, 200, 120, 0.6));
    margin-top: 6px;
  }
  .hv-card .card-label {
    font-family: var(--serif);
    font-size: 9px;
    letter-spacing: 2.5px;
    color: #f0c878;
    text-transform: uppercase;
    text-align: center;
    font-weight: 600;
    text-shadow: 0 0 6px rgba(240, 200, 120, 0.5);
    padding-bottom: 4px;
    position: relative;
  }
  /* Decorative line above the label */
  .hv-card .card-label::before {
    content: '';
    position: absolute;
    top: -4px;
    left: 25%; right: 25%;
    height: 0.5px;
    background: linear-gradient(90deg, transparent, rgba(240, 200, 120, 0.7), transparent);
  }
  .hv-card-1 {
    top: 2%; right: -2%;
    transform: rotate(8deg);
    animation-delay: 0s;
    width: 110px;
  }
  .hv-card-2 {
    top: 34%; right: -10%;
    transform: rotate(-6deg);
    animation-delay: -2s;
    width: 118px;
  }
  .hv-card-3 {
    top: 64%; right: 6%;
    transform: rotate(12deg);
    animation-delay: -4s;
    width: 100px;
  }

  @keyframes floatY {
    0%, 100% { transform: translateY(0) rotate(var(--rot, 0deg)); }
    50% { transform: translateY(-12px) rotate(var(--rot, 0deg)); }
  }
  .hv-card-1 { --rot: 8deg; }
  .hv-card-2 { --rot: -6deg; }
  .hv-card-3 { --rot: 12deg; }

  /* ============ STATS BAR (white card) ============ */
  .stats-bar-wrap {
    position: relative;
    margin-top: -80px;
    z-index: 5;
    padding: 0 32px;
  }
  .stats-bar {
    background: var(--bg-white);
    border-radius: 16px;
    padding: 32px 40px;
    display: grid;
    grid-template-columns: repeat(4, 1fr);
    gap: 0;
    box-shadow: var(--shadow-lg);
    max-width: 1280px;
    margin: 0 auto;
    position: relative;
  }
  .stat-item {
    display: flex;
    flex-direction: column;
    align-items: center;
    text-align: center;
    padding: 0 20px;
    border-right: 1px solid var(--border-light);
    position: relative;
  }
  .stat-item:last-child { border-right: none; }
  .stat-icon {
    width: 48px;
    height: 48px;
    border-radius: 50%;
    background: linear-gradient(135deg, rgba(212, 162, 76, 0.15), rgba(212, 162, 76, 0.05));
    display: grid;
    place-items: center;
    color: var(--cosmic-purple);
    margin-bottom: 12px;
  }
  .stat-icon svg { width: 24px; height: 24px; }
  .stat-num {
    font-family: var(--serif);
    font-size: 36px;
    font-weight: 600;
    color: var(--ink);
    line-height: 1;
    margin-bottom: 4px;
    letter-spacing: -0.5px;
  }
  .stat-label {
    font-size: 13px;
    color: var(--ink-muted);
    letter-spacing: 0.3px;
  }

  /* ============ SECTION TITLES ============ */
  .section-header {
    text-align: center;
    margin-bottom: 48px;
  }
  .section-title {
    font-family: var(--serif);
    font-size: clamp(32px, 4vw, 44px);
    font-weight: 500;
    color: var(--ink);
    line-height: 1.1;
    letter-spacing: -0.5px;
    margin-bottom: 14px;
    position: relative;
    display: inline-block;
  }
  .section-title::after {
    content: '';
    position: absolute;
    bottom: -10px;
    left: 50%;
    transform: translateX(-50%);
    width: 80px;
    height: 2px;
    background: linear-gradient(90deg, transparent, var(--gold), transparent);
  }
  .section-sub {
    font-size: 15.5px;
    color: var(--ink-muted);
    max-width: 600px;
    margin: 24px auto 0;
    line-height: 1.7;
  }

  /* ============ COURSES SECTION ============ */
  .courses-section {
    padding: 100px 0 60px;
  }
  .courses-grid {
    display: grid;
    grid-template-columns: repeat(4, 1fr);
    gap: 22px;
  }
  .course-card {
    background: var(--bg-white);
    border-radius: 16px;
    overflow: hidden;
    box-shadow: var(--shadow-sm);
    transition: all 0.4s;
    display: flex;
    flex-direction: column;
    border: 1px solid var(--border-light);
  }
  .course-card:hover {
    transform: translateY(-6px);
    box-shadow: var(--shadow-lg);
  }
  .course-visual {
    aspect-ratio: 1.4 / 1;
    position: relative;
    overflow: hidden;
    background: linear-gradient(160deg, #2a1f5e, #0a0618);
    display: grid;
    place-items: center;
  }
  .course-visual::before {
    content: '';
    position: absolute;
    inset: 0;
    background:
      radial-gradient(circle at 30% 30%, rgba(240, 200, 120, 0.3), transparent 50%),
      radial-gradient(1px 1px at 20% 30%, rgba(255,255,255,0.6), transparent),
      radial-gradient(1px 1px at 80% 70%, rgba(240,200,120,0.5), transparent),
      radial-gradient(1px 1px at 50% 20%, rgba(255,255,255,0.5), transparent),
      radial-gradient(1px 1px at 70% 50%, rgba(240,200,120,0.4), transparent);
    background-size: 100% 100%, 200px 200px, 200px 200px, 200px 200px, 200px 200px;
  }
  .course-visual svg {
    width: 60%;
    height: 60%;
    color: var(--gold-bright);
    position: relative;
    z-index: 2;
    filter: drop-shadow(0 0 20px rgba(240, 200, 120, 0.4));
  }
  .course-body {
    padding: 22px 22px 24px;
    display: flex;
    flex-direction: column;
    flex: 1;
  }
  .course-head-row {
    display: flex;
    align-items: center;
    gap: 8px;
    margin-bottom: 8px;
  }
  .course-head-row svg {
    width: 18px;
    height: 18px;
    color: var(--gold);
    flex-shrink: 0;
  }
  .course-title {
    font-family: var(--serif);
    font-size: 22px;
    font-weight: 600;
    color: var(--ink);
    letter-spacing: -0.3px;
    text-align: center;
    width: 100%;
    margin-bottom: 8px;
  }
  .course-desc {
    font-size: 13px;
    color: var(--ink-muted);
    line-height: 1.6;
    text-align: center;
    margin-bottom: 16px;
    min-height: 60px;
  }
  .course-meta {
    display: flex;
    justify-content: center;
    align-items: center;
    gap: 8px;
    padding: 10px 0;
    border-top: 1px solid var(--border-light);
    border-bottom: 1px solid var(--border-light);
    margin-bottom: 16px;
    font-size: 12px;
    color: var(--ink-soft);
    font-weight: 500;
  }
  .course-meta .dot {
    width: 4px;
    height: 4px;
    background: var(--gold);
    border-radius: 50%;
  }
  .course-cta {
    margin-top: auto;
    padding: 11px 20px;
    background: linear-gradient(135deg, var(--gold-bright), var(--gold));
    color: #1a0f00;
    border-radius: 8px;
    text-decoration: none;
    font-weight: 600;
    font-size: 13px;
    text-align: center;
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 8px;
    transition: all 0.3s;
    border: none;
    cursor: pointer;
  }
  .course-cta:hover {
    box-shadow: 0 6px 16px rgba(212, 162, 76, 0.4);
    transform: translateY(-1px);
  }

  /* ============ WHY CHOOSE ============ */
  .why-section {
    padding: 60px 0 100px;
  }
  .why-grid {
    display: grid;
    grid-template-columns: repeat(4, 1fr);
    gap: 18px;
  }
  .why-card {
    background: var(--bg-white);
    border: 1px solid var(--border-light);
    border-radius: 14px;
    padding: 22px 22px;
    display: flex;
    align-items: center;
    gap: 16px;
    transition: all 0.3s;
    box-shadow: var(--shadow-sm);
  }
  .why-card:hover {
    transform: translateY(-4px);
    box-shadow: var(--shadow-md);
    border-color: var(--border-gold);
  }
  .why-icon {
    width: 52px;
    height: 52px;
    border-radius: 12px;
    display: grid;
    place-items: center;
    flex-shrink: 0;
    color: white;
  }
  .why-icon svg { width: 26px; height: 26px; }
  .why-icon-1 { background: linear-gradient(135deg, #4a2f8e, #2a1f5e); }
  .why-icon-2 { background: linear-gradient(135deg, #d4a24c, #a8791f); }
  .why-icon-3 { background: linear-gradient(135deg, #2a1f5e, #4a2f8e); }
  .why-icon-4 { background: linear-gradient(135deg, #c4847a, #8b4f5e); }
  .why-content h3 {
    font-family: var(--sans);
    font-size: 15px;
    color: var(--ink);
    font-weight: 600;
    margin-bottom: 4px;
    letter-spacing: -0.2px;
  }
  .why-content p {
    font-size: 12.5px;
    color: var(--ink-muted);
    line-height: 1.5;
  }

  /* ============ CAREER JOURNEY (cosmic dark panel) ============ */
  .journey-section {
    padding: 60px 0 100px;
  }
  .journey-panel {
    background:
      radial-gradient(ellipse at top right, rgba(74, 47, 142, 0.4), transparent 60%),
      radial-gradient(ellipse at bottom left, rgba(212, 162, 76, 0.1), transparent 60%),
      linear-gradient(160deg, #1a1535, #0a0618);
    border-radius: 20px;
    padding: 60px 60px;
    color: #faf5ea;
    position: relative;
    overflow: hidden;
    box-shadow: var(--shadow-cosmic);
  }
  .journey-panel::before {
    content: '';
    position: absolute;
    inset: 0;
    background:
      radial-gradient(1px 1px at 20% 30%, rgba(255,255,255,0.6), transparent),
      radial-gradient(1px 1px at 80% 60%, rgba(240,200,120,0.5), transparent),
      radial-gradient(1px 1px at 50% 20%, rgba(255,255,255,0.5), transparent),
      radial-gradient(1px 1px at 70% 80%, rgba(240,200,120,0.4), transparent);
    background-size: 300px 300px;
    opacity: 0.6;
    pointer-events: none;
  }
  .journey-title {
    text-align: center;
    margin-bottom: 50px;
    position: relative;
  }
  .journey-title h2 {
    font-family: var(--serif);
    font-size: clamp(30px, 3.5vw, 40px);
    color: #faf5ea;
    font-weight: 500;
    letter-spacing: -0.5px;
    margin-bottom: 12px;
  }
  .journey-title h2 em { font-style: italic; color: var(--gold-bright); font-weight: 300; }
  .journey-title p {
    color: #c4bba8;
    font-size: 15px;
    max-width: 600px;
    margin: 0 auto;
  }
  .journey-steps {
    display: grid;
    grid-template-columns: repeat(4, 1fr);
    gap: 20px;
    position: relative;
  }
  .jstep-card {
    background: rgba(255, 255, 255, 0.04);
    border: 1px solid rgba(212, 162, 76, 0.2);
    border-radius: 14px;
    padding: 28px 24px;
    backdrop-filter: blur(10px);
    transition: all 0.3s;
    position: relative;
  }
  .jstep-card:hover {
    border-color: var(--gold);
    background: rgba(212, 162, 76, 0.06);
    transform: translateY(-4px);
  }
  .jstep-num {
    width: 44px;
    height: 44px;
    border-radius: 50%;
    background: linear-gradient(135deg, var(--gold-bright), var(--gold));
    color: #1a0f00;
    display: grid;
    place-items: center;
    font-family: var(--serif);
    font-size: 20px;
    font-weight: 700;
    margin-bottom: 18px;
    box-shadow: 0 4px 14px rgba(212, 162, 76, 0.4);
  }
  .jstep-icon {
    position: absolute;
    top: 24px;
    right: 24px;
    width: 32px;
    height: 32px;
    color: var(--gold-bright);
    opacity: 0.7;
  }
  .jstep-card h4 {
    font-family: var(--serif);
    font-size: 22px;
    color: #faf5ea;
    margin-bottom: 10px;
    font-weight: 500;
    letter-spacing: -0.3px;
  }
  .jstep-card p {
    font-size: 13.5px;
    color: #c4bba8;
    line-height: 1.6;
  }

  /* ============ TESTIMONIALS ============ */
  .testi-section {
    padding: 60px 0 100px;
  }
  .testi-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    margin-bottom: 50px;
  }
  .testi-header .section-title {
    margin: 0;
    text-align: left;
  }
  .testi-header .section-title::after {
    left: 0;
    transform: none;
  }
  .testi-nav {
    display: flex;
    gap: 10px;
  }
  .testi-nav-btn {
    width: 44px;
    height: 44px;
    border-radius: 50%;
    background: var(--bg-white);
    border: 1px solid var(--border-light);
    display: grid;
    place-items: center;
    cursor: pointer;
    transition: all 0.3s;
    color: var(--ink);
    box-shadow: var(--shadow-sm);
  }
  .testi-nav-btn:hover {
    background: var(--cosmic-deep);
    color: white;
    border-color: var(--cosmic-deep);
  }
  .testi-nav-btn svg { width: 18px; height: 18px; }

  .testi-grid {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: 22px;
  }
  .testi-card {
    background: var(--bg-white);
    border: 1px solid var(--border-light);
    border-radius: 14px;
    padding: 28px 28px 24px;
    box-shadow: var(--shadow-sm);
    transition: all 0.3s;
  }
  .testi-card:hover {
    transform: translateY(-4px);
    box-shadow: var(--shadow-md);
  }
  .testi-top {
    display: flex;
    align-items: center;
    gap: 14px;
    margin-bottom: 16px;
  }
  .testi-avatar {
    width: 52px;
    height: 52px;
    border-radius: 50%;
    display: grid;
    place-items: center;
    font-family: var(--serif);
    font-weight: 600;
    color: #1a0f00;
    font-size: 18px;
    flex-shrink: 0;
  }
  .testi-avatar-1 { background: linear-gradient(135deg, var(--gold-bright), #c4847a); }
  .testi-avatar-2 { background: linear-gradient(135deg, var(--gold), #8b6a4f); }
  .testi-avatar-3 { background: linear-gradient(135deg, #c4847a, #7a4f9e); color: white; }
  .testi-name {
    font-family: var(--sans);
    font-size: 15px;
    color: var(--ink);
    font-weight: 600;
    margin-bottom: 2px;
  }
  .testi-role {
    font-size: 12px;
    color: var(--ink-muted);
  }
  .testi-quote {
    font-size: 14px;
    color: var(--ink-soft);
    line-height: 1.65;
    margin-bottom: 16px;
    font-style: italic;
  }
  .testi-stars {
    display: flex;
    gap: 3px;
    color: var(--gold);
    font-size: 14px;
    letter-spacing: 1px;
  }

  /* ============ CTA / FORM (cosmic purple) ============ */
  .cta-section {
    padding: 60px 0 0;
  }
  .cta-panel {
    background:
      radial-gradient(ellipse at left center, rgba(74, 47, 142, 0.4), transparent 60%),
      radial-gradient(ellipse at right top, rgba(212, 162, 76, 0.1), transparent 50%),
      linear-gradient(135deg, #1a1535, #2a1f5e 50%, #0a0618);
    border-radius: 20px 20px 0 0;
    padding: 70px 70px;
    position: relative;
    overflow: hidden;
    color: #faf5ea;
    box-shadow: var(--shadow-cosmic);
  }
  .cta-panel::before {
    content: '';
    position: absolute;
    inset: 0;
    background:
      radial-gradient(1px 1px at 20% 30%, rgba(255,255,255,0.5), transparent),
      radial-gradient(1px 1px at 80% 70%, rgba(240,200,120,0.4), transparent),
      radial-gradient(1px 1px at 50% 20%, rgba(255,255,255,0.4), transparent);
    background-size: 400px 400px;
    opacity: 0.5;
    pointer-events: none;
  }
  .cta-inner {
    display: grid;
    grid-template-columns: 1fr 1.1fr;
    gap: 60px;
    align-items: center;
    position: relative;
    z-index: 2;
  }
  .cta-left h2 {
    font-family: var(--serif);
    font-size: clamp(34px, 4vw, 48px);
    line-height: 1.1;
    color: #faf5ea;
    font-weight: 500;
    letter-spacing: -0.5px;
    margin-bottom: 20px;
  }
  .cta-left p {
    font-size: 15.5px;
    color: #c4bba8;
    margin-bottom: 32px;
    line-height: 1.7;
    max-width: 420px;
  }
  .cta-buttons {
    display: flex;
    gap: 14px;
  }

  /* Lotus mandala decoration */
  .lotus-deco {
    position: absolute;
    left: -80px;
    top: 50%;
    transform: translateY(-50%);
    width: 380px;
    height: 380px;
    opacity: 0.15;
    pointer-events: none;
    color: var(--gold-bright);
  }

  /* Form */
  .cta-form-card {
    background: rgba(10, 6, 24, 0.6);
    border: 1px solid rgba(212, 162, 76, 0.3);
    border-radius: 14px;
    padding: 32px;
    backdrop-filter: blur(10px);
    position: relative;
    z-index: 2;
  }
  .cta-form-card h3 {
    font-family: var(--serif);
    font-size: 22px;
    color: #faf5ea;
    margin-bottom: 6px;
    font-weight: 500;
  }
  .cta-form-card .sub {
    font-size: 13px;
    color: #a89d87;
    margin-bottom: 22px;
  }
  .form-row-2 {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 12px;
    margin-bottom: 12px;
  }
  .form-input-group {
    position: relative;
  }
  .form-input-group svg {
    position: absolute;
    left: 14px;
    top: 50%;
    transform: translateY(-50%);
    width: 16px;
    height: 16px;
    color: #a89d87;
    pointer-events: none;
  }
  .form-input-group input,
  .form-input-group select {
    width: 100%;
    padding: 13px 14px 13px 40px;
    background: rgba(255,255,255,0.05);
    border: 1px solid rgba(255, 255, 255, 0.12);
    color: #faf5ea;
    font-family: var(--sans);
    font-size: 13.5px;
    border-radius: 8px;
    transition: all 0.3s;
  }
  .form-input-group input::placeholder { color: #7a7060; }
  .form-input-group input:focus,
  .form-input-group select:focus {
    outline: none;
    border-color: var(--gold);
    background: rgba(255, 255, 255, 0.08);
  }
  .form-input-group select option { color: #1a1535; background: var(--bg-white); }
  .cta-submit {
    width: 100%;
    margin-top: 4px;
    padding: 14px;
    justify-content: center;
    border-radius: 8px;
  }

  /* ============ FOOTER ============ */
  footer {
    background: var(--cosmic-deep);
    color: #c4bba8;
    padding: 50px 0 28px;
  }
  .foot-grid {
    display: flex;
    align-items: center;
    justify-content: space-between;
    flex-wrap: wrap;
    gap: 32px;
    padding-bottom: 28px;
    border-bottom: 1px solid rgba(212, 162, 76, 0.15);
  }
  .foot-links {
    display: flex;
    gap: 32px;
    flex-wrap: wrap;
  }
  .foot-links a {
    color: #c4bba8;
    text-decoration: none;
    font-size: 14px;
    transition: color 0.3s;
  }
  .foot-links a:hover { color: var(--gold-bright); }
  .foot-socials {
    display: flex;
    gap: 10px;
  }
  .foot-socials a {
    width: 36px;
    height: 36px;
    border-radius: 50%;
    border: 1px solid rgba(212, 162, 76, 0.3);
    display: grid;
    place-items: center;
    color: var(--gold);
    text-decoration: none;
    transition: all 0.3s;
  }
  .foot-socials a:hover { background: var(--gold); color: var(--cosmic-deep); }
  .foot-socials svg { width: 16px; height: 16px; }
  .foot-bottom {
    padding-top: 24px;
    text-align: center;
    font-size: 12.5px;
    color: #7a7060;
    letter-spacing: 0.5px;
  }

  /* ============ RESPONSIVE ============ */
  @media (max-width: 1024px) {
    nav ul { display: none; }
    .hero-inner { grid-template-columns: 1fr; gap: 50px; text-align: center; }
    .hero-visual { margin: 0 auto; }
    .hero-ctas { justify-content: center; }
    .student-row { justify-content: center; }
    .stats-bar { grid-template-columns: repeat(2, 1fr); gap: 24px 0; padding: 28px; }
    .stat-item:nth-child(2) { border-right: none; }
    .stat-item:nth-child(1), .stat-item:nth-child(2) { padding-bottom: 24px; border-bottom: 1px solid var(--border-light); }
    .courses-grid { grid-template-columns: repeat(2, 1fr); }
    .why-grid { grid-template-columns: repeat(2, 1fr); }
    .journey-steps { grid-template-columns: repeat(2, 1fr); }
    .testi-grid { grid-template-columns: 1fr; }
    .cta-inner { grid-template-columns: 1fr; gap: 40px; }
    .cta-panel { padding: 48px 32px; }
    .journey-panel { padding: 40px 28px; }
    .lotus-deco { display: none; }
    .testi-header { flex-direction: column; align-items: flex-start; gap: 20px; }
  }
  @media (max-width: 640px) {
    .container { padding: 0 18px; }
    .stats-bar-wrap { padding: 0 18px; }
    .stats-bar { grid-template-columns: 1fr; padding: 24px; }
    .stat-item { border-right: none !important; padding: 20px 0 !important; border-bottom: 1px solid var(--border-light); }
    .stat-item:last-child { border-bottom: none; }
    .courses-grid { grid-template-columns: 1fr; }
    .why-grid { grid-template-columns: 1fr; }
    .journey-steps { grid-template-columns: 1fr; }
    .form-row-2 { grid-template-columns: 1fr; }
    .hero h1 { font-size: 40px; }
    .hero-ctas { flex-direction: column; }
    .btn { width: 100%; justify-content: center; }
    .cta-buttons { flex-direction: column; width: 100%; }
    .nav-right .btn { padding: 8px 14px; font-size: 11px; }
    .foot-grid { flex-direction: column; text-align: center; }
    .foot-links { justify-content: center; gap: 18px 24px; }
  }

  /* ============ WHY CHOOSE — UPGRADED 6-CARD COSMIC GRID ============ */
  .why-grid-v2 {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: 22px;
  }
  .why-card-v2 {
    position: relative;
    background:
      radial-gradient(ellipse at top, rgba(74, 47, 142, 0.5), transparent 60%),
      linear-gradient(160deg, #1a1535 0%, #0a0618 100%);
    border: 1px solid rgba(212, 162, 76, 0.2);
    border-radius: 18px;
    padding: 36px 30px 32px;
    text-align: center;
    color: #faf5ea;
    transition: all 0.4s ease;
    overflow: hidden;
  }
  .why-card-v2::before {
    content: '';
    position: absolute;
    inset: 0;
    background:
      radial-gradient(1px 1px at 30% 20%, rgba(255,255,255,0.4), transparent),
      radial-gradient(1px 1px at 70% 80%, rgba(240,200,120,0.5), transparent);
    background-size: 120px 120px;
    opacity: 0.4;
    pointer-events: none;
  }
  .why-card-v2:hover {
    transform: translateY(-6px);
    border-color: var(--gold);
    box-shadow: 0 30px 60px rgba(74, 47, 142, 0.4), 0 0 30px rgba(212, 162, 76, 0.15);
  }
  .why-card-v2 .why-icon-v2 {
    width: 64px;
    height: 64px;
    margin: 0 auto 22px;
    border-radius: 50%;
    background: radial-gradient(circle, rgba(212, 162, 76, 0.25), rgba(212, 162, 76, 0.05));
    border: 1px solid rgba(212, 162, 76, 0.4);
    display: grid;
    place-items: center;
    color: var(--gold-bright);
    position: relative;
    z-index: 1;
  }
  .why-card-v2 .why-icon-v2 svg { width: 30px; height: 30px; }
  .why-card-v2 h3 {
    font-family: var(--serif);
    font-size: 20px;
    color: var(--gold-bright);
    font-weight: 500;
    margin-bottom: 12px;
    position: relative;
    z-index: 1;
  }
  .why-card-v2 p {
    font-size: 13.5px;
    color: #c4bba8;
    line-height: 1.65;
    position: relative;
    z-index: 1;
  }

  /* ============ GLOBALLY RECOGNIZED CERTIFICATE ============ */
  .cert-section {
    padding: 60px 0 100px;
  }
  .cert-grid {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 50px;
    align-items: center;
  }
  .cert-panel {
    background:
      radial-gradient(ellipse at top right, rgba(74, 47, 142, 0.45), transparent 60%),
      radial-gradient(ellipse at bottom left, rgba(212, 162, 76, 0.12), transparent 60%),
      linear-gradient(160deg, #1a1535, #0a0618);
    border: 1px solid rgba(212, 162, 76, 0.2);
    border-radius: 20px;
    padding: 50px 50px;
    color: #faf5ea;
    position: relative;
    overflow: hidden;
