<script>
  // Smooth fade-in observer
  const observer = new IntersectionObserver((entries) => {
    entries.forEach(entry => {
      if (entry.isIntersecting) {
        entry.target.style.opacity = '1';
        entry.target.style.transform = 'translateY(0)';
      }
    });
  }, { threshold: 0.1 });

  document.querySelectorAll('.course-card, .why-card, .why-card-v2, .jstep-card, .review-card, .stat-item, .faq-item, .cert-panel, .cert-display, .startup-panel, .dpiit-cert').forEach(el => {
    el.style.opacity = '0';
    el.style.transform = 'translateY(30px)';
    el.style.transition = 'opacity 0.7s ease-out, transform 0.7s ease-out';
    observer.observe(el);
  });

  // FAQ accordion
  document.querySelectorAll('.faq-q').forEach(q => {
    q.addEventListener('click', () => {
      const item = q.parentElement;
      const wasOpen = item.classList.contains('open');
      document.querySelectorAll('.faq-item').forEach(i => i.classList.remove('open'));
      if (!wasOpen) item.classList.add('open');
    });
  });

  // Reviews carousel — simple cycle through reviews on prev/next
  const reviewsGrid = document.querySelector('.reviews-grid');
  if (reviewsGrid) {
    const cards = Array.from(reviewsGrid.children);
    const prev = document.querySelector('.review-nav-prev');
    const next = document.querySelector('.review-nav-next');
    let idx = 0;
    const cycle = (dir) => {
      idx = (idx + dir + cards.length) % cards.length;
      // rotate the order: take from idx onward, then beginning
      const reordered = [...cards.slice(idx), ...cards.slice(0, idx)];
      reorderedAnimated();
      function reorderedAnimated() {
        cards.forEach(c => c.style.transition = 'opacity 0.25s, transform 0.25s');
        cards.forEach(c => { c.style.opacity = '0'; c.style.transform = 'translateY(10px)'; });
        setTimeout(() => {
          reviewsGrid.innerHTML = '';
          reordered.forEach(c => reviewsGrid.appendChild(c));
          requestAnimationFrame(() => {
            cards.forEach(c => { c.style.opacity = '1'; c.style.transform = 'translateY(0)'; });
          });
        }, 250);
      }
    };
    prev && prev.addEventListener('click', () => cycle(-1));
    next && next.addEventListener('click', () => cycle(1));
  }

  // Open first FAQ by default for visual completeness
  const firstFaq = document.querySelector('.faq-item');
  if (firstFaq) firstFaq.classList.add('open');
</script>
<script src="https://cdn.jsdelivr.net/npm/bootstrap@5.3.2/dist/js/bootstrap.bundle.min.js"></script>
